function isValid(s) {
    const stack = [];
    for (const ch of s) {
        const code = ch.charCodeAt(0);
        const isOpen = ch === '(' || ch === '[' || code === 123;
        if (isOpen) {
            stack.push(ch);
            continue;
        }

        if (stack.length === 0) return false;
        const top = stack.pop();

        const closeParen = ch === ')' && top !== '(';
        const closeBracket = ch === ']' && top !== '[';
        const closeBrace = code === 125 && top.charCodeAt(0) !== 123;
        if (closeParen || closeBracket || closeBrace) return false;
    }
    return stack.length === 0;
}

