        return isValidHelper(s, 0, 0);
    }
    private boolean isValidHelper(String s, int index, int balance) {
        if (index == s.length()) {
            return balance == 0;
        }
        char current = s.charAt(index);
        if (current == '(') {
            return isValidHelper(s, index + 1, balance + 1);
        }
        else if (current == ')') {
            return balance > 0 && isValidHelper(s, index + 1, balance - 1);
        }
        else {
            return isValidHelper(s, index + 1, balance);
        }
    }
