package main

import "fmt"

func isValid(s string) bool {
    return backtrack(s, "", 0)
}

func backtrack(s, current string, index int) bool {
    if index == len(s) {
        return current == ""
    }

    if s[index] == '(' {
        return backtrack(s, current+"(", index+1) || backtrack(s, current, index+1)
    } else if s[index] == ')' {
        if len(current) > 0 && current[len(current)-1] == '(' {
            return backtrack(s, current[:len(current)-1], index+1) || backtrack(s, current, index+1)
        }
        return backtrack(s, current, index+1)
    }

    return false
}

func main() {
    fmt.Println(isValid("()"))       // true
    fmt.Println(isValid("()[]{}"))   // true
    fmt.Println(isValid("(]"))       // false
    fmt.Println(isValid("([)]"))     // false
    fmt.Println(isValid("{[]}"))     // true
}

